"use client";

import { useRef, useState } from "react";
import type { EnvironmentVariableEntry } from "@/components/control-ui/lib/env-file";
import {
  collectEnvironmentVariables,
  createEmptyEnvironmentVariableEntry,
  getDuplicateEnvironmentVariableKeys,
  parseEnvFileText,
  readEnvFile,
  rowsToEnvFileText,
} from "@/components/control-ui/lib/env-file";

export type EnvironmentVariableRow = EnvironmentVariableEntry;

export type EnvironmentVariablesImportMode = "auto" | "bulk";

export interface UseEnvironmentVariablesOptions<TRow extends EnvironmentVariableRow = EnvironmentVariableRow> {
  initialRows?: readonly TRow[];
  rows?: readonly TRow[];
  onRowsChange?: (rows: TRow[]) => void;
  createDefaultRow?: () => TRow;
  createRow?: (entry: EnvironmentVariableEntry) => TRow;
  getEditableRows?: (rows: readonly TRow[]) => readonly TRow[];
  getPreservedRows?: (rows: readonly TRow[]) => readonly TRow[];
  maxUploadSize?: number;
}

export interface EnvironmentVariablesFileUploadEvent {
  target: {
    files?: FileList | readonly File[] | null;
    value: string;
  };
}

export interface EnvironmentVariablesImportOptions {
  targetIndex?: number;
  mode?: EnvironmentVariablesImportMode;
}

export interface EnvironmentVariablesController<TRow extends EnvironmentVariableRow = EnvironmentVariableRow> {
  rows: readonly TRow[];
  uploadError: string | null;
  duplicateKeys: Set<string>;
  hasDuplicateKeys: boolean;
  isDirty: boolean;
  setRows: (rows: readonly TRow[]) => TRow[];
  resetRows: (rows?: readonly TRow[]) => TRow[];
  appendRow: (row?: TRow) => TRow[];
  updateRow: (index: number, patch: Partial<EnvironmentVariableEntry>) => TRow[];
  removeRow: (index: number) => TRow[];
  getRowsForSubmit: () => TRow[];
  getEnvironmentVariablesForSubmit: () => Record<string, string>;
  getEnvFileTextForSubmit: () => string;
  importText: (text: string, options?: EnvironmentVariablesImportOptions) => boolean;
  handleFileUpload: (event: EnvironmentVariablesFileUploadEvent) => Promise<void>;
  handlePaste: (index: number, text: string) => boolean;
  clearUploadError: () => void;
  getRowId: (index: number) => string;
  isValueRevealed: (index: number) => boolean;
  toggleValueVisibility: (index: number) => void;
  rowHasDuplicateKey: (index: number) => boolean;
}

function defaultCreateRow(entry: EnvironmentVariableEntry): EnvironmentVariableRow {
  return { key: entry.key, value: entry.value };
}

function defaultEditableRows<TRow extends EnvironmentVariableRow>(rows: readonly TRow[]) {
  return rows;
}

function defaultPreservedRows() {
  return [];
}

function normalizeRows<TRow extends EnvironmentVariableRow>(rows: readonly TRow[] | undefined, createDefaultRow: () => TRow) {
  return rows && rows.length > 0 ? rows.map((row) => ({ ...row })) : [createDefaultRow()];
}

function hasOnlyEmptyRow(rows: readonly EnvironmentVariableEntry[]) {
  if (rows.length !== 1) return false;
  const [firstRow] = rows;
  if (!firstRow) return false;
  return !firstRow.key.trim() && !firstRow.value;
}

function areRowsEqual(a: readonly EnvironmentVariableEntry[], b: readonly EnvironmentVariableEntry[]) {
  if (a.length !== b.length) return false;

  for (let index = 0; index < a.length; index++) {
    const aRow = a[index];
    const bRow = b[index];
    if (!aRow || !bRow || aRow.key !== bRow.key || aRow.value !== bRow.value) {
      return false;
    }
  }

  return true;
}

// Generic overload keeps the public contract; the implementation works on plain entries so the
// default row factories type-check without casts. Custom TRow callers supply their own factories.
export function useEnvironmentVariables<TRow extends EnvironmentVariableRow = EnvironmentVariableRow>(
  options?: UseEnvironmentVariablesOptions<TRow>,
): EnvironmentVariablesController<TRow>;
export function useEnvironmentVariables({
  initialRows,
  rows: controlledRows,
  onRowsChange,
  createDefaultRow = createEmptyEnvironmentVariableEntry,
  createRow = defaultCreateRow,
  getEditableRows = defaultEditableRows,
  getPreservedRows = defaultPreservedRows,
  maxUploadSize,
}: UseEnvironmentVariablesOptions<EnvironmentVariableRow> = {}): EnvironmentVariablesController<EnvironmentVariableRow> {
  const initialSourceRows = controlledRows ?? initialRows;
  const nextRowId = useRef(0);
  const fallbackRowIds = useRef<Record<number, string>>({});
  const [uncontrolledRows, setUncontrolledRows] = useState(() => normalizeRows(initialSourceRows, createDefaultRow));
  const [baselineRows, setBaselineRows] = useState(() => normalizeRows(initialSourceRows, createDefaultRow));
  const [rowIds, setRowIds] = useState(() => normalizeRows(initialSourceRows, createDefaultRow).map(() => createRowId()));
  const [uploadError, setUploadError] = useState<string | null>(null);
  const [revealedValues, setRevealedValues] = useState<Record<number, boolean>>({});

  const rows = controlledRows ? normalizeRows(controlledRows, createDefaultRow) : uncontrolledRows;
  const editableRows = (sourceRows: readonly EnvironmentVariableRow[] = rows) => getEditableRows(sourceRows);
  const preservedRows = (sourceRows: readonly EnvironmentVariableRow[] = rows) => getPreservedRows(sourceRows);

  function createRowId() {
    const rowId = nextRowId.current;
    nextRowId.current += 1;
    return `environment-variable-row-${rowId}`;
  }

  function commitRows(nextRows: readonly EnvironmentVariableRow[], nextRowIds?: readonly string[]) {
    const normalizedRows = normalizeRows(nextRows, createDefaultRow);
    const normalizedRowIds = normalizedRows.map((_, index) => nextRowIds?.[index] ?? rowIds[index] ?? createRowId());

    if (!controlledRows) {
      setUncontrolledRows(normalizedRows);
    }

    setRowIds(normalizedRowIds);
    onRowsChange?.(normalizedRows);
    return normalizedRows;
  }

  function setRows(nextRows: readonly EnvironmentVariableRow[]) {
    return commitRows(nextRows);
  }

  function resetRows(nextRows: readonly EnvironmentVariableRow[] = baselineRows) {
    const normalizedRows = normalizeRows(nextRows, createDefaultRow);
    commitRows(
      normalizedRows,
      normalizedRows.map(() => createRowId()),
    );
    setBaselineRows(normalizedRows);
    setRevealedValues({});
    setUploadError(null);
    return normalizedRows;
  }

  function getRowsForSubmit() {
    return [...rows];
  }

  function appendRow(row = createDefaultRow()) {
    return commitRows([...rows, row], [...rowIds, createRowId()]);
  }

  function updateRow(index: number, patch: Partial<EnvironmentVariableEntry>) {
    return commitRows(
      rows.map((row, rowIndex) => (rowIndex === index ? { ...row, ...patch } : row)),
      rowIds,
    );
  }

  function removeRow(index: number) {
    const nextRows = rows.filter((_, rowIndex) => rowIndex !== index);
    const nextRowIds = rowIds.filter((_, rowIndex) => rowIndex !== index);
    setRevealedValues({});
    return commitRows(nextRows.length > 0 ? nextRows : [createDefaultRow()], nextRows.length > 0 ? nextRowIds : [createRowId()]);
  }

  function mergeParsedRows(parsedRows: readonly EnvironmentVariableEntry[], targetIndex?: number) {
    const newRows = parsedRows.map(createRow);
    const newRowIds = newRows.map(() => createRowId());
    const currentEditableRows = editableRows(rows);

    if (hasOnlyEmptyRow(currentEditableRows)) {
      const preserved = preservedRows(rows);
      return commitRows([...preserved, ...newRows], [...rowIds.slice(0, preserved.length), ...newRowIds]);
    }

    if (typeof targetIndex !== "number") {
      return commitRows([...rows, ...newRows], [...rowIds, ...newRowIds]);
    }

    const targetRow = rows[targetIndex];
    if (!targetRow) {
      return commitRows([...rows, ...newRows], [...rowIds, ...newRowIds]);
    }

    const targetIsEmpty = !targetRow.key.trim() && !targetRow.value;
    const before = rows.slice(0, targetIndex + (targetIsEmpty ? 0 : 1));
    const after = rows.slice(targetIndex + 1);
    const beforeIds = rowIds.slice(0, targetIndex + (targetIsEmpty ? 0 : 1));
    const afterIds = rowIds.slice(targetIndex + 1);
    return commitRows([...before, ...newRows, ...after], [...beforeIds, ...newRowIds, ...afterIds]);
  }

  function importText(text: string, options: EnvironmentVariablesImportOptions = {}) {
    const entries = parseEnvironmentVariablesImportText(text, options.mode ?? "bulk");
    if (entries.length === 0) return false;

    mergeParsedRows(entries, options.targetIndex);
    setRevealedValues({});
    setUploadError(null);
    return true;
  }

  function handlePaste(index: number, text: string) {
    return importText(text, { targetIndex: index, mode: "auto" });
  }

  async function handleFileUpload(event: EnvironmentVariablesFileUploadEvent) {
    setUploadError(null);
    const file = event.target.files?.[0];
    if (!file) return;

    const result = await readEnvFile(file, { maxSize: maxUploadSize });
    if (!result.ok) {
      setUploadError(result.error);
      event.target.value = "";
      return;
    }

    mergeParsedRows(result.entries);
    setRevealedValues({});

    event.target.value = "";
  }

  function getRowId(index: number) {
    const rowId = rowIds[index] ?? fallbackRowIds.current[index];
    if (rowId) return rowId;

    const fallbackRowId = createRowId();
    fallbackRowIds.current[index] = fallbackRowId;
    return fallbackRowId;
  }

  const duplicateKeys = getDuplicateEnvironmentVariableKeys(rows);
  const rowsDirty = !areRowsEqual(rows, baselineRows);

  return {
    rows,
    uploadError,
    duplicateKeys,
    hasDuplicateKeys: duplicateKeys.size > 0,
    isDirty: rowsDirty,
    setRows,
    resetRows,
    appendRow,
    updateRow,
    removeRow,
    getRowsForSubmit,
    getEnvironmentVariablesForSubmit: () => collectEnvironmentVariables(getRowsForSubmit()),
    getEnvFileTextForSubmit: () => rowsToEnvFileText(getRowsForSubmit()),
    importText,
    handleFileUpload,
    handlePaste,
    clearUploadError: () => setUploadError(null),
    getRowId,
    isValueRevealed: (index) => Boolean(revealedValues[index]),
    toggleValueVisibility: (index) => setRevealedValues((previous) => ({ ...previous, [index]: !previous[index] })),
    rowHasDuplicateKey: (index) => duplicateKeys.has(rows[index]?.key.trim() ?? ""),
  };
}

export function parseEnvironmentVariablesImportText(text: string, mode: EnvironmentVariablesImportMode = "bulk") {
  const trimmedText = text.trim();
  if (!trimmedText.includes("=")) return [];

  const entries = parseEnvFileText(trimmedText);
  if (entries.length === 0) return [];
  if (mode === "bulk") return entries;

  const firstAssignmentLooksLikeEnvVar = /^(?:export\s+)?[A-Z_][A-Z0-9_]*\s*=/.test(trimmedText);
  const hasBulkShape = entries.length > 1 || trimmedText.includes("\n") || firstAssignmentLooksLikeEnvVar;

  return hasBulkShape ? entries : [];
}

export interface EnvironmentVariableEntry {
  key: string;
  value: string;
}

export const ENV_FILE_MAX_SIZE = 64 * 1024;
export const DUPLICATE_ENVIRONMENT_VARIABLE_MESSAGE = "Environment variable keys must be unique";

export class DuplicateEnvironmentVariableKeyError extends Error {
  constructor(public readonly key: string) {
    super(DUPLICATE_ENVIRONMENT_VARIABLE_MESSAGE);
    this.name = "DuplicateEnvironmentVariableKeyError";
  }
}

export function createEmptyEnvironmentVariableEntry(): EnvironmentVariableEntry {
  return { key: "", value: "" };
}

export function rowsFromEnvironmentVariables(envVars: Record<string, unknown> | undefined): EnvironmentVariableEntry[] {
  const entries = Object.entries(envVars ?? {});
  return entries.length > 0 ? entries.map(([key, value]) => ({ key, value: String(value) })) : [createEmptyEnvironmentVariableEntry()];
}

export function getDuplicateEnvironmentVariableKeys(rows: readonly EnvironmentVariableEntry[]): Set<string> {
  const seen = new Set<string>();
  const duplicates = new Set<string>();

  for (const row of rows) {
    const key = row.key.trim();
    if (!key) continue;

    if (seen.has(key)) {
      duplicates.add(key);
    } else {
      seen.add(key);
    }
  }

  return duplicates;
}

export function collectEnvironmentVariables(rows: readonly EnvironmentVariableEntry[]): Record<string, string> {
  const envVars: Record<string, string> = {};
  const seen = new Set<string>();

  for (const row of rows) {
    const key = row.key.trim();
    if (!key) continue;

    if (seen.has(key)) {
      throw new DuplicateEnvironmentVariableKeyError(key);
    }

    seen.add(key);
    envVars[key] = row.value;
  }

  return envVars;
}

function parseEnvAssignment(line: string): { key: string; rawValue: string } | undefined {
  const normalizedLine = line.trim();
  if (!normalizedLine || normalizedLine.startsWith("#")) return undefined;

  const stripped = normalizedLine.replace(/^export\s+/, "");
  const equalsIndex = stripped.indexOf("=");
  if (equalsIndex === -1) return undefined;

  const key = stripped.slice(0, equalsIndex).trim();
  if (!key) return undefined;
  return { key, rawValue: stripped.slice(equalsIndex + 1) };
}

function openingQuote(value: string): '"' | "'" | undefined {
  if (value.startsWith('"')) return '"';
  if (value.startsWith("'")) return "'";
  return undefined;
}

function parseUnquotedEnvValue(rawValue: string): string {
  const commentIndex = rawValue.indexOf(" #");
  return (commentIndex === -1 ? rawValue : rawValue.slice(0, commentIndex)).trim();
}

function parseQuotedEnvValue(lines: string[], lineIndex: number, value: string, quote: '"' | "'") {
  const closingIndex = findClosingQuoteIndex(value, quote, 1);
  if (closingIndex !== -1) {
    return { value: unescapeQuotedValue(value.slice(1, closingIndex), quote), nextLineIndex: lineIndex + 1 };
  }

  const parts = [value.slice(1)];
  let nextLineIndex = lineIndex + 1;
  while (nextLineIndex < lines.length) {
    const nextLine = lines[nextLineIndex];
    if (nextLine === undefined) break;
    const endIndex = findClosingQuoteIndex(nextLine, quote);
    if (endIndex !== -1) {
      parts.push(nextLine.slice(0, endIndex));
      nextLineIndex += 1;
      break;
    }
    parts.push(nextLine);
    nextLineIndex += 1;
  }

  return { value: unescapeQuotedValue(parts.join("\n"), quote), nextLineIndex };
}

function parseEnvValue(lines: string[], lineIndex: number, rawValue: string) {
  const value = rawValue.trimStart();
  const quote = openingQuote(value);
  if (quote) return parseQuotedEnvValue(lines, lineIndex, value, quote);
  return { value: parseUnquotedEnvValue(rawValue), nextLineIndex: lineIndex + 1 };
}

export function parseEnvFileText(text: string): EnvironmentVariableEntry[] {
  const results: EnvironmentVariableEntry[] = [];
  const lines = text.replace(/^\uFEFF/, "").split(/\r?\n/);
  let lineIndex = 0;

  while (lineIndex < lines.length) {
    const currentLine = lines[lineIndex];
    if (currentLine === undefined) break;
    const assignment = parseEnvAssignment(currentLine);
    if (!assignment) {
      lineIndex++;
      continue;
    }

    const parsedValue = parseEnvValue(lines, lineIndex, assignment.rawValue);
    results.push({ key: assignment.key, value: parsedValue.value });
    lineIndex = parsedValue.nextLineIndex;
  }

  return results;
}

function findClosingQuoteIndex(value: string, quote: '"' | "'", startIndex = 0): number {
  for (let index = startIndex; index < value.length; index++) {
    if (value[index] === quote && !isEscaped(value, index)) {
      return index;
    }
  }
  return -1;
}

function isEscaped(value: string, index: number): boolean {
  let slashCount = 0;
  for (let cursor = index - 1; cursor >= 0 && value[cursor] === "\\"; cursor--) {
    slashCount++;
  }
  return slashCount % 2 === 1;
}

const DOUBLE_QUOTED_CONTROL_ESCAPES: Readonly<Record<string, string | undefined>> = {
  n: "\n",
  r: "\r",
  t: "\t",
};

function escapedQuotedCharacter(next: string, quote: '"' | "'"): string | undefined {
  if (next === quote || next === "\\") return next;
  if (quote === "'") return undefined;
  return DOUBLE_QUOTED_CONTROL_ESCAPES[next];
}

function unescapeQuotedValue(value: string, quote: '"' | "'"): string {
  let result = "";

  for (let index = 0; index < value.length; index++) {
    const current = value[index];
    const next = value[index + 1];

    if (current !== "\\" || next === undefined) {
      result += current;
      continue;
    }

    const unescaped = escapedQuotedCharacter(next, quote);
    result += unescaped ?? current;
    if (unescaped !== undefined) index++;
  }

  return result;
}

function escapeDoubleQuotedValue(value: string): string {
  return value.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
}

function shouldQuoteValue(value: string) {
  return value.includes("\n") || value.includes("\r") || value.includes(" #") || /^\s|\s$/.test(value);
}

export function rowsToEnvFileText(rows: readonly EnvironmentVariableEntry[]): string {
  const lines: string[] = [];

  for (const row of rows) {
    const key = row.key.trim();
    if (!key) continue;

    const value = row.value;
    lines.push(shouldQuoteValue(value) ? `${key}="${escapeDoubleQuotedValue(value)}"` : `${key}=${value}`);
  }

  return lines.join("\n");
}

export async function readEnvFile(
  file: File,
  options: { maxSize?: number } = {},
): Promise<{ ok: true; entries: EnvironmentVariableEntry[] } | { ok: false; error: string }> {
  const maxSize = options.maxSize ?? ENV_FILE_MAX_SIZE;

  if (file.size > maxSize) {
    return { ok: false, error: `File is too large (max ${Math.ceil(maxSize / 1024)} KB).` };
  }

  let text: string;
  try {
    text = await readFileText(file);
  } catch {
    return { ok: false, error: "Could not read the selected file. Please try again." };
  }

  if (text.includes("\0")) {
    return { ok: false, error: "File appears to be binary. Please import a plain-text .env file." };
  }

  const entries = parseEnvFileText(text);
  if (entries.length === 0) {
    return { ok: false, error: "No valid environment variables found in the file." };
  }

  return { ok: true, entries };
}

async function readFileText(file: File): Promise<string> {
  if (typeof file.text === "function") {
    try {
      return await file.text();
    } catch {
      // Some test DOMs expose Blob.text without implementing every Blob source.
    }
  }

  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      if (typeof reader.result === "string") {
        resolve(reader.result);
      } else {
        reject(new Error("FileReader returned non-text content."));
      }
    };
    reader.onerror = () => reject(reader.error ?? new Error("FileReader failed."));
    reader.readAsText(file);
  });
}

"use client";

import { AlertTriangleIcon, EyeIcon, EyeOffIcon, FileUpIcon, PlusIcon, RotateCcwIcon, SaveIcon, Trash2Icon } from "lucide-react";
import type { ChangeEvent, ClipboardEvent, ComponentProps, ReactNode, SubmitEvent } from "react";
import { createContext, use, useId } from "react";

import {
  type EnvironmentVariableRow,
  type EnvironmentVariablesController,
  type UseEnvironmentVariablesOptions,
  useEnvironmentVariables,
} from "@/components/control-ui/hooks/use-environment-variables";
import { cn } from "@/components/control-ui/lib/cn";
import {
  collectEnvironmentVariables,
  DUPLICATE_ENVIRONMENT_VARIABLE_MESSAGE,
  rowsToEnvFileText,
} from "@/components/control-ui/lib/env-file";
import { Button } from "@/components/control-ui/ui/button";
import { Input } from "@/components/control-ui/ui/input";
import { InputGroup, InputGroupAddon, InputGroupInput } from "@/components/control-ui/ui/input-group";

export type EnvironmentVariablesRowErrors = Record<number, { key?: ReactNode; value?: ReactNode }>;

export type EnvironmentVariablesSubmitPayload<TRow extends EnvironmentVariableRow = EnvironmentVariableRow> = {
  rows: TRow[];
  variables: Record<string, string>;
  envFileText: string;
  reset: () => void;
};

type EnvironmentVariablesRenderController = EnvironmentVariablesController<EnvironmentVariableRow>;

type EnvironmentVariablesContextValue = {
  editor: EnvironmentVariablesRenderController;
  disabled: boolean;
  readOnly: boolean;
  rowErrors?: EnvironmentVariablesRowErrors;
  keyLabel: ReactNode;
  valueLabel: ReactNode;
  keyPlaceholder: string;
  valuePlaceholder: string;
  duplicateKeyMessage: ReactNode;
};

const EnvironmentVariablesContext = createContext<EnvironmentVariablesContextValue | null>(null);

function useEnvironmentVariablesContext(componentName: string) {
  const context = use(EnvironmentVariablesContext);
  if (!context) throw new Error(`${componentName} must be used inside <EnvironmentVariables.Root>.`);
  return context;
}

export type EnvironmentVariablesRootProps<TRow extends EnvironmentVariableRow = EnvironmentVariableRow> = Omit<
  ComponentProps<"form">,
  "onSubmit"
> & {
  editor: EnvironmentVariablesController<TRow>;
  disabled?: boolean;
  readOnly?: boolean;
  rowErrors?: EnvironmentVariablesRowErrors;
  keyLabel?: ReactNode;
  valueLabel?: ReactNode;
  keyPlaceholder?: string;
  valuePlaceholder?: string;
  duplicateKeyMessage?: ReactNode;
  onSubmit?: (payload: EnvironmentVariablesSubmitPayload<TRow>) => void | Promise<void>;
};

export function EnvironmentVariablesRoot<TRow extends EnvironmentVariableRow = EnvironmentVariableRow>({
  editor,
  disabled = false,
  readOnly = false,
  rowErrors,
  keyLabel = "Key",
  valueLabel = "Value",
  keyPlaceholder = "OPENAI_API_KEY",
  valuePlaceholder = "sk-...",
  duplicateKeyMessage = DUPLICATE_ENVIRONMENT_VARIABLE_MESSAGE,
  onSubmit,
  className,
  children,
  ...props
}: EnvironmentVariablesRootProps<TRow>) {
  function handleSubmit(event: SubmitEvent<HTMLFormElement>) {
    if (event.defaultPrevented || !onSubmit) return;

    event.preventDefault();
    if (editor.hasDuplicateKeys) return;

    const rows = editor.getRowsForSubmit();
    const payload = {
      rows,
      variables: collectEnvironmentVariables(rows),
      envFileText: rowsToEnvFileText(rows),
      reset: () => editor.resetRows(rows),
    } satisfies EnvironmentVariablesSubmitPayload<TRow>;

    void onSubmit(payload);
  }

  return (
    <EnvironmentVariablesContext.Provider
      value={{
        editor: editor as unknown as EnvironmentVariablesRenderController,
        disabled,
        readOnly,
        rowErrors,
        keyLabel,
        valueLabel,
        keyPlaceholder,
        valuePlaceholder,
        duplicateKeyMessage,
      }}
    >
      <form
        data-control-ui="environment-variables"
        data-slot="root"
        data-surface="panel"
        data-disabled={disabled ? "true" : undefined}
        data-readonly={readOnly ? "true" : undefined}
        className={cn("flex min-w-0 flex-col gap-4", className)}
        onSubmit={handleSubmit}
        {...props}
      >
        {children}
      </form>
    </EnvironmentVariablesContext.Provider>
  );
}

export type EnvironmentVariablesProps<TRow extends EnvironmentVariableRow = EnvironmentVariableRow> = Omit<
  EnvironmentVariablesRootProps<TRow>,
  "editor"
> &
  UseEnvironmentVariablesOptions<TRow> & {
    editor?: EnvironmentVariablesController<TRow>;
    title?: ReactNode;
    description?: ReactNode;
    error?: ReactNode;
    submitLabel?: ReactNode;
    resetLabel?: ReactNode;
    addLabel?: ReactNode;
    hideDefaultActions?: boolean;
  };

function EnvironmentVariablesComponent<TRow extends EnvironmentVariableRow = EnvironmentVariableRow>({
  editor: providedEditor,
  initialRows,
  rows,
  onRowsChange,
  createDefaultRow,
  createRow,
  getEditableRows,
  getPreservedRows,
  maxUploadSize,
  title = "Environment variables",
  description,
  error,
  submitLabel = "Save",
  resetLabel = "Reset",
  addLabel = "Add variable",
  hideDefaultActions = false,
  children,
  onSubmit,
  ...props
}: EnvironmentVariablesProps<TRow>) {
  const internalEditor = useEnvironmentVariables({
    initialRows,
    rows,
    onRowsChange,
    createDefaultRow,
    createRow,
    getEditableRows,
    getPreservedRows,
    maxUploadSize,
  });
  const editor = providedEditor ?? internalEditor;

  return (
    <EnvironmentVariablesRoot editor={editor} onSubmit={onSubmit} {...props}>
      {children ?? (
        <>
          <EnvironmentVariablesHeader title={title} description={description} />
          <EnvironmentVariablesToolbar />
          <EnvironmentVariablesUploadError />
          <EnvironmentVariablesRows />
          <EnvironmentVariablesDuplicateKeysError />
          <EnvironmentVariablesMessage error={error} />
          {!hideDefaultActions && (
            <EnvironmentVariablesActions>
              <EnvironmentVariablesAddButton>{addLabel}</EnvironmentVariablesAddButton>
              <div className="flex min-w-0 items-center gap-2">
                <EnvironmentVariablesResetButton>{resetLabel}</EnvironmentVariablesResetButton>
                {onSubmit ? <EnvironmentVariablesSubmitButton>{submitLabel}</EnvironmentVariablesSubmitButton> : null}
              </div>
            </EnvironmentVariablesActions>
          )}
        </>
      )}
    </EnvironmentVariablesRoot>
  );
}

export type EnvironmentVariablesHeaderProps = ComponentProps<"div"> & {
  title?: ReactNode;
  description?: ReactNode;
};

export function EnvironmentVariablesHeader({ title, description, className, children, ...props }: EnvironmentVariablesHeaderProps) {
  if (children) {
    return (
      <div data-control-ui="environment-variables" data-slot="header" className={cn("flex flex-col gap-1", className)} {...props}>
        {children}
      </div>
    );
  }

  if (!title && !description) return null;

  return (
    <div data-control-ui="environment-variables" data-slot="header" className={cn("flex flex-col gap-1", className)} {...props}>
      {title ? <div className="text-label font-semibold text-foreground">{title}</div> : null}
      {description ? <div className="max-w-2xl text-meta text-muted-foreground">{description}</div> : null}
    </div>
  );
}

export type EnvironmentVariablesToolbarProps = ComponentProps<"div">;

export function EnvironmentVariablesToolbar({ className, children, ...props }: EnvironmentVariablesToolbarProps) {
  const { readOnly } = useEnvironmentVariablesContext("EnvironmentVariables.Toolbar");
  if (readOnly) return null;

  return (
    <div
      data-control-ui="environment-variables"
      data-slot="toolbar"
